import requests
import json

KONG_ADMIN_URL = 'http://localhost:8001'  # Replace with your actual Kong Admin API URL

# Creating services
services = [{"name": "service1", "url": "http://example.com"}]
for service in services:
    response = requests.post(f"{KONG_ADMIN_URL}/services/", data=json.dumps(service), headers={'Content-Type': 'application/json'})
    print(response.status_code)
    if response.status_code != 201:
        print(f"Error creating service {service['name']}: ", response.text)

# Creating routes
routes = [{"name": "route1", "paths": ["/api/endpoint"], "methods": ["GET"], "service": {"id": "486c7a23-76d0-4f9e-b513-eaf96e4eaca4"}}]  # Replace service id with actual one
for route in routes:
    response = requests.post(f"{KONG_ADMIN_URL}/routes/", data=json.dumps(route), headers={'Content-Type': 'application/json'})
    print(response.status_code)
    if response.status_code != 201:
        print(f"Error creating route {route['name']}: ", response.text)

# Creating upstreams and targets
upstreams = [{"name": "upstream1", "slots": 100}]
targets = [{"target": "example.com", "weight": 10, "tags": ["tag1"]}, {"target": "example2.com", "weight": 90, "tags": ["tag2"]}]
for upstream in upstreams:
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/", data=json.dumps(upstream), headers={'Content-Type': 'application/json'})
    print(response.status_code)
    if response.status_code != 201:
        print(f"Error creating upstream {upstream['name']}: ", response.text)
    else:  # Add targets to the created upstream
        for target in targets:
            target["upstream"] = {"id": upstream["name"]}
            response = requests.post(f"{KONG_ADMIN_URL}/targets/", data=json.dumps(target), headers={'Content-Type': 'application/json'})
            print(response.status_code)
            if response.status_code != 201:
                print(f"Error creating target {target['target']} for upstream {upstream['name']}: ", response.text)